ValidationRule.errorConditionFormula:
AND( /* Run only if GST is entered */ NOT(ISBLANK(DRC_NBC_GST_Number__c)),
/* Country must be India */ TEXT(DRC_NBC_Address__CountryCode__s) = "IN",
/* Run validation if either State Code OR PAN mismatch */ OR( /* State Code Mismatch */ LEFT(DRC_NBC_GST_Number__c, 2) <> CASE( TEXT(DRC_NBC_Address__StateCode__s), "KA", "29", "MH", "27", "DL", "07", "GJ", "24", "TN", "33", "WB", "19", "UP", "09", "RJ", "08", "PB", "03", "KL", "32", "MP", "23", "HR", "06", "HP", "02", "JH", "20", "OD", "21", "CG", "22", "AS", "18", "AP", "37", "TS", "36", "BR", "10", "GA", "30", "AR", "12", "" /* default if state not found */ ),
/* PAN Number Mismatch (case-insensitive, trimmed) */ UPPER(TRIM(MID(DRC_NBC_GST_Number__c, 3, 10))) <> UPPER(TRIM(DRC_NBC_Account__r.DRC_NBC_PAN_No__c)) ) )
